allQuestions.stream()
            .map(question -> {
                InterviewAnswerEntity answer = answerMap.get(question.questionIndex());
                if (answer != null) {
                    // 用户已回答，使用答案数据
                    return interviewMapper.toAnswerDetailDTO(answer, extractKeyPoints(answer));
                } else {
                    // 用户未回答，构建空答案
                    return new InterviewDetailDTO.AnswerDetailDTO(
                        question.questionIndex(),
                        question.question(),
                        question.category(),
                        null,  // userAnswer
                        question.score() != null ? question.score() : 0,  // score
                        question.feedback(),  // feedback
                        null,  // referenceAnswer
                        null,  // keyPoints
                        null   // answeredAt
                    );
                }
            }).toList

sessions.stream()
            .map(InterviewSessionEntity::getQuestionsJson)//取出其中的question json。::是方法应用，可以装话为lambda表达式:: 是方法引用，等价于 session -> session.getQuestionsJson()
            .filter(json -> json != null && !json.isEmpty())//过滤掉空json
             //flatmap是一对多转换并把转换后结果铺平为一维，普通map一般是二维的（一般是一次对话的问题归为一行，每一列对应一次对话）
            .flatMap(json -> {//将所有问题转换为一个个的history question数据类对象
                try {
                    //将json字段转化为DTO类对象
                    List<InterviewQuestionDTO> questions = objectMapper.readValue(json,
                        new TypeReference<List<InterviewQuestionDTO>>() {});
                    return questions.stream()
                        .filter(q -> !q.isFollowUp())//过滤掉追问问题
                        .map(q -> new HistoricalQuestion(q.question(), q.type(), q.topicSummary()));//这一步转化为history question。
                } catch (Exception e) {
                    log.error("解析历史问题JSON失败", e);
                    return java.util.stream.Stream.<HistoricalQuestion>empty();
                }
            })
            .filter(hq -> seen.add(hq.question()))//对于多个对话问题间去重（利用LinkedHashSet集合特性，顺序录入且不能重复）
            .limit(MAX_HISTORICAL_QUESTIONS).toList

